import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第二十一章 十战九败","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第二十一章-十战九败.md","filePath":"永恒道途/正文/第一卷-山门有路/第二十一章-十战九败.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第二十一章-十战九败.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第二十一章-十战九败" tabindex="-1">第二十一章 十战九败 <a class="header-anchor" href="#第二十一章-十战九败" aria-label="Permalink to &quot;第二十一章 十战九败&quot;">​</a></h1><p>入剑峰第四个月，李清风给陈玄列了一张对战单。</p><p>十个人。</p><p>刀、枪、符、阵、体修各有，境界最低炼气七层，最高九层。每十日一战，不计名次，不许提前购买私人消息。对手只需在开战前报备法器与公开境界，其他都由陈玄站上练剑坪后自己看。</p><p>“七宗会武还有五个月。”李清风道，“你在宗内大比看见的，多是被你提前研究过的人。出了山门，没人替你把前三场记录装进储物袋。”</p><p>“十战要赢几场？”</p><p>“没有要求。”</p><p>“那如何核课业？”</p><p>“每场回来写三件事：你以为对方会做什么，对方真正做了什么，下一次先改哪一步。”李清风把名单背面翻给他，“胜负排在第四栏。”</p><p>不是不看胜负。</p><p>只是胜负不能替前三栏回答。</p><p>第一战，对剑峰炼气八层弟子魏迟。</p><p>魏迟用重剑，开场前只说自己右手为主。陈玄看他肩背宽厚，以为会正面压剑，第一步便提前向外切。魏迟却将重剑插地，以剑身为盾，左手连续三道金刃封路。</p><p>陈玄绕开的不是重剑。</p><p>是自己预想中的重剑。</p><p>第二十三招，金刃割破小腿；第三十一招，重剑才第一次离地，将他连剑带人拍出练剑坪。</p><p>第一败。</p><p>他在册上写：把兵器形状当作打法；下一次先看灵力如何走，不先看剑有多重。</p><p>第二战，对符峰炼气七层弟子许楠。</p><p>许楠腰间挂四只符袋，开场后却一张符也没用，只以短棍贴身。陈玄花十五招防火符，等发现对方真正想逼自己退到预埋缚足符的位置，右脚已经被黄光钉住。</p><p>第二败。</p><p>第三战，灵兽峰弟子没有带灵兽上坪，只用一只训兽铜哨扰乱听觉。陈玄以为哨声控制某种暗器，分神找了二十息，被一拳打中胸口。</p><p>第三败。</p><p>前三场没有一场输在剑不够快。</p><p>都输在他急着把陌生东西解释成已经见过的东西。</p><p>王道全听说规则后很不满意。</p><p>“不许买私人消息，那我的生意怎么办？”</p><p>“你可以卖公开境界。”</p><p>“公开的谁付钱？”</p><p>“所以这五个月不赚我的。”</p><p>王道全摇着扇子想了半天，最终换了一种生意。他去找十名陪练，各收一份“战后复盘费”，把陈玄写下的前三栏经本人同意后抄给对手。魏迟这才知道，陈玄第一眼只看见自己的重剑；许楠则在下一次比斗里换掉了符袋位置。</p><p>“你两边收钱？”陈玄问。</p><p>“你这边没收。”</p><p>“我的复盘成了你的货。”</p><p>“名字和掌天瓶一样保密。”王道全说到一半，自己停住，“掌什么？”</p><p>“账本。”</p><p>“我说的是账本。”</p><p>两人对视片刻，王道全扇子摇得快了一些。陈玄把话题记在心里，没有当场追问他究竟是口误还是试探。王道全也没有再说。</p><p>关系越近，边界越不能靠装作没听见维持。</p><p>当晚交易时，陈玄直问：“你是否知道我有一件催药的东西？”</p><p>王道全的扇子慢下来。</p><p>“知道你药龄稳定得不正常，种类却在变；知道你不偷宗门药圃，也不肯加量。具体是什么，不知道。”</p><p>“为何不查？”</p><p>“查明白以后，别人抓我时便能从我嘴里问明白。”王道全把本月货款推来，“我做的是你的药材生意，不是你秘密的生意。”</p><p>“方才为何说掌字？”</p><p>“坊市有人打听一种掌形药瓶，我顺嘴混了。”</p><p>这句未必全真。</p><p>陈玄没有继续逼问，只将本月交易量从一株减到半株，告诉王道全不是惩罚，是风险重新核算。王道全点头接受，也将收货价提高半成，补偿自己可能知道得太多带来的风险。</p><p>账外之交没有因为关系久了便从此不用再算。</p><p>第四战，对阵峰炼气八层弟子。</p><p>陈玄不再猜阵法名称，先看阵旗落点与对方每次换诀时哪一面灵光变暗。他撑到一炷香末，仍因少看见藏在坪外竹影中的第四面小旗落败。</p><p>第四败。</p><p>第五战，对药堂医修。</p><p>对方先在空气里散无色麻粉，再以银针逼他加快呼吸。陈玄辨出药味，却判断错了风向，左手麻痹后主动认输。</p><p>第五败。</p><p>第六战，对体修。</p><p>他没有等护体灵光出现周期，而用前三剑迫使对方选择护眼、护膝或护喉。第三剑终于让左肋短暂空出，陈玄刺中，却因境界差距没能破甲，反被抱摔出坪。</p><p>第六败。</p><p>这次李清风在册上只写了一句：路造出来了，剑还不够。</p><p>陈玄没有把“剑还不够”理解成再加一百剑。</p><p>他开始练同一落点下三种不同力度。三分力用于问路，五分力逼位，七分力破防。每一次都留三分归身，不再让第一道全力剑芒把后续选择掏空。</p><p>入峰第六个月，四气损耗第二次复测。</p><p>金火经过旧伤处的散失已经缩到一成半，水木不足一成。李清风这才允许他每十日服一份调和丹，并将聚灵阵时辰从每月五日增到七日。</p><p>掌天瓶半年凝出六滴绿液。</p><p>两滴催熟自用养脉药，两滴催熟不同种类低阶药材交给王道全，剩余两滴封存。养脉药只是配合日常训练修复细小损耗，不替他直接增长修为；聚灵阵、行气纠错、内门灵米与近十四个月的炼气六层积累，才一点点填满丹田气旋。</p><p>第七个月末，六层关隘自然松动。</p><p>陈玄没有选在十战中的某一战前突破，也没有用一场胜负当作契机。他停战十日，先做第三轮量灵，再服半份养气丹。四属灵气依次入周天，气旋经过九次扩缩，终于稳在更大一层。</p><p>炼气七层。</p><p>破境后前三日不对战，只做空刺与调息。第四日，李清风以枯枝试他三十招。</p><p>陈玄逼得师父向右移了半步，自己被点中六次。</p><p>“七层让你的剑芒从五尺到七尺。”李清风道，“没有让第四面阵旗自动亮给你看。”</p><p>“弟子知道。”</p><p>“那便继续输。”</p><p>第七战，对炼气九层双刀修。</p><p>陈玄在六十招内三次逼出对方换手，仍因灵力不足被刀背点中咽喉。</p><p>第七败。</p><p>第八战，对水系法修。</p><p>他用火气蒸开水幕，视线恢复，却忽略水汽凝在青锋护手，换剑时手滑半寸。</p><p>第八败。</p><p>第九战，对魏迟第二次。</p><p>重剑仍先插地，金刃却不再从左手出。魏迟把金刃藏入剑脊阵纹，等陈玄以为自己改掉第一次误判时才引爆。</p><p>陈玄挡住金刃，重剑本身随后离地。</p><p>他比第一次多撑二十七招，最终仍被拍出坪外。</p><p>第九败。</p><p>十战只剩最后一场。</p><p>对手张远，炼气八层，双刀一长一短。公开记录里，他长刀主攻、短刀补隙；真正站上坪后，短刀第一招便主动刺向中线，长刀反而一直封退路。</p><p>陈玄没有急着给这种变化取名。</p><p>第一剑只问右路。</p><p>张远不走。</p><p>第二剑问左路。</p><p>张远仍不走，以短刀正面点开青锋。</p><p>第三剑，陈玄斩向两人之间的空地。</p><p>张远第一次皱眉。</p><p>那一剑没有攻击目标，也没有封现成退路，看上去什么都没换到。可青芒散去的位置，恰好让张远长刀无法从最顺的角度向右回旋。他若继续站着，下一剑会压短刀；若向后，陈玄能占擂心。</p><p>张远向左前进。</p><p>陈玄等到了回答。</p><p>青锋第二段不追人，只封左前下一步。张远长刀回切，陈玄留在身内的三分灵力立刻转腕，第三剑从中线真正递出。</p><p>短刀被压。</p><p>长刀尚未回。</p><p>剑尖停在张远胸口。</p><p>第十战，胜。</p><p>没有突然悟道，也没有境界碾压。张远看着胸前剑尖，先回想了前三剑。</p><p>“你第一剑斩空，是故意？”</p><p>“那一剑在问你要不要继续站。”</p><p>“我若不向左？”</p><p>“重新问。”</p><p>张远收刀：“李首座那句‘剑不一定每一招都要赚到东西’，今日拿我作了注解。”</p><p>陈玄摇头：“第一剑已经赚到了答案。”</p><p>十战九败。</p><p>册子最后一页没有写“终于证明自己”。陈玄把第十战的误判也照样记下：他没料到张远会向左前进，只是第二剑恰能封住；若对方右退，原本准备的第三剑来不及转。</p><p>胜局也要拆。</p><p>否则它比败局更容易骗人。</p><p>宗门名额选拔在一个半月后开始。</p><p>这一个半月里，陈玄没有再临时加陪练数量。他把九场败局按误判来源重新分成兵器、地形、用药、阵法与节奏五类，每类只挑一处先改；第十场的胜法则让张远换左右刀位各试三次，确认那一剑不是只能对一个站位生效。</p><p>二十七名年轻弟子争五席。陈玄第一轮对灵兽峰炼气七层弟子，第二轮遇符峰炼气八层，第三轮则再次对张远。</p><p>张远已经知道那三剑。</p><p>陈玄没有照搬。第一剑仍斩空，第二剑却直接归中，让张远为了防左前而多留的长刀落在无用处。两人交手七十余招，陈玄以剑柄点中短刀腕，拿到第四个名额。</p><p>另外四人是叶承、秦岚、张远与李明月。</p><p>张远虽败给陈玄，仍在复选中取第五。名额赛不是一次输了便从此被定义，他也没有因同一招第二次受骗便失去资格。</p><p>苏婉没有参加选拔。</p><p>她此前闭关冲击筑基，出关已错过报名。宗门依旧没有因宗主之女身份把别人名额挪给她，只给一个随队医修与候补席。她接受，没有要求补试。筑基初期的修为让她在队伍中最高，职责却先写着伤员记录、赛前验药与突发替补。</p><p>会武出发前夜，李清风没有让陈玄练剑。</p><p>师徒坐在古松下吃药粥。九个月过去，粥已经从能入口变成味道尚可，李清风切肉的厚薄仍没什么进步。</p><p>“血魔子也在血魔宗名单。”李清风道，“筑基初期。”</p><p>陈玄停筷。</p><p>“若抽中？”</p><p>“认输。”</p><p>“一剑不试？”</p><p>“擂台不是档房，不需要你用身体再核一次境界差距。”李清风看着他，“炼气七层正面对筑基初期，十战十败。护阵与裁判能降低死的机会，不能让你多一个大境界。”</p><p>“那如何看他的功法？”</p><p>“看他与别人打。记他的血气如何起、刀从哪里收、失控时先护什么。你去会武是争名额，也是看路，不是非要把每一条路都用胸口走一遍。”</p><p>陈玄想起自己那本十战册。</p><p>九败都亲自站过。</p><p>血魔子这一败，不必站。</p><p>“弟子记住。”</p><p>“另外，若他用黑风山的事激你，不回话。”</p><p>“为什么？”</p><p>“你知道陆炳能走，郑衡能重新布阵。活人的近况不必交给仇人评说。”</p><p>李清风把一只纸包推来。里面不是法器，而是鲁老头做的灵谷饼，边缘烤得有些焦。</p><p>“他让带的？”</p><p>“他说剑峰面难吃。”</p><p>陈玄掰开一块。熟悉的谷香里混着一点烟味。</p><p>三日后，青云宗飞舟抵达断岳古城。</p><p>古城以黑铁岩筑墙，远望像一道横卧平原的山脊。七宗会武期间，四面城门悬起长旗，商队、散修与各宗弟子沿官道汇入。街边不再只有低阶丹药，一些铺面已摆出筑基修士用的灵器，鉴药人也多有炼气后期修为。</p><p>王道全自费跟着坊市商队来了。</p><p>“三年一届，三十五名弟子的输赢养活半条赌坊街。”他腰间挂四只钱袋，扇面换成“落子无悔”，“我若不来，这些年学的账岂不白做？”</p><p>“带了多少灵石？”</p><p>“不能说。”</p><p>“会押我？”</p><p>“看对手。若是血魔子，我押你认输。”</p><p>“认输也有盘口？”</p><p>“只要有人肯赌，什么都有。”</p><p>断岳战台位于城中。</p><p>三十六根阵柱围住白岩擂台，七宗席位在北侧依次展开。观众没有旧稿里模糊的“数万人齐声”，只是不同方向的话叠在一起，像持续不退的潮。卖签、报赔率、核兵器与找座位的声音各不相同。</p><p>血魔宗旗升起时，青云席位静了一层。</p><p>五名血魔宗弟子穿暗红袍，为首青年披黑色外氅，脸色苍白，双手干净，指甲边缘没有半点血污。他落座前先抚平袖口，随后才把血色长刀放到膝上。</p><p>陈玄背后旧钩伤传来极轻刺感。</p><p>不是伤势复发。</p><p>是同源血煞靠近后的残余反应。</p><p>血魔子。</p><p>那是称号，不是名字。血魔宗可以把它给一个候选，也可以在候选失败后收回。黑风山数处血阵，正是他用来积累血气战绩的一部分。</p><p>对方似有所觉，目光越过两宗席位，准确落在陈玄身上。</p><p>他没有动怒，反而先拿白巾擦了擦本就干净的指尖。</p><p>“黑风山回来的人？”他隔着战台问。</p><p>声音不高，附近席位却听得见。</p><p>陈玄没有回答。</p><p>陆炳如今能拄杖走一里，郑衡的新阵盘不再把退路阵钉放在同一处。这些事不需要说给一个把外门弟子当血阵材料的人听。</p><p>血魔子等了两息，收回目光，像只是确认一件物品是否到场。</p><p>苏婉站在随队医席旁：“旧伤有反应？”</p><p>“一息，已退。”</p><p>“记下来。若持续超过十息，说明场内有血阵或血煞外放，不要只当情绪。”</p><p>她先把时间写入伤单，没有问陈玄怕不怕。</p><p>会武钟响，第一轮抽签开启。</p><p>七宗共三十五人，一人轮空，其余两两对战。竹签从阵盘中依次升起，宗名与姓名投在白岩上。</p><p>第一擂第一场。</p><p>青云宗陈玄，对玄岳宗石鸣。</p><p>石鸣炼气八层，土系体修，双臂套玄铁护臂。看到签名后，他没有说什么药园第三，也没有问黑风山传闻，只走到擂台边验过陈玄公开境界。</p><p>“炼气七层。”</p><p>“是。”</p><p>“听说你十场输了九场。”</p><p>消息已经传出青云宗。</p><p>陈玄拔出青锋剑：“是真的。”</p><p>石鸣将护臂相击，土黄阵纹逐一亮起：“那我按九场准备。”</p><p>他没有急着把自己当成唯一的胜局。</p><p>陈玄也没有。</p><p>裁判抬手。</p><p>断岳古城的风从三十六根阵柱间穿过，吹动七面宗旗。</p><p>陈玄握剑，先看石鸣脚下第一道土纹如何落地。</p><p>第十一战，尚未开始。</p><p>（第二十一章完）</p>',190)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
